module top_module(
  input [3:0] in0,
  input [3:0] in1,
  input [3:0] in2,
  input [3:0] in3,
  input [1:0] sel,
  input en,
  output [3:0] out
);wire [3:0] demux_in;

  assign demux_in[0] = (sel == 2'b00) ? in0[0] : (sel == 2'b01) ? in1[0] : (sel == 2'b10) ? in2[0] : in3[0];
  assign demux_in[1] = (sel == 2'b00) ? in0[1] : (sel == 2'b01) ? in1[1] : (sel == 2'b10) ? in2[1] : in3[1];
  assign demux_in[2] = (sel == 2'b00) ? in0[2] : (sel == 2'b01) ? in1[2] : (sel == 2'b10) ? in2[2] : in3[2];
  assign demux_in[3] = (sel == 2'b00) ? in0[3] : (sel == 2'b01) ? in1[3] : (sel == 2'b10) ? in2[3] : in3[3];

  assign out = (en == 1'b1) ? demux_in : 4'b0000;

endmodule
